<span class="line"><span style="color:#A6ACCD;">LOCAL_REGISTRY=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">localhost:5000</span><span style="color:#89DDFF;">&quot;</span></span>
